(() => {
  const canvas = document.querySelectorAll('canvas')[0];
  const gl = canvas.getContext('webgl2') || canvas.getContext('webgl');
  if (!gl) return { error: 'no gl' };

  // Read a small region from center of screen (where beads should be)
  const pixels = new Uint8Array(4);
  gl.readPixels(640, 400, 1, 1, gl.RGBA, gl.UNSIGNED_BYTE, pixels);

  // Also read top-left (should be sky blue #87ceeb = rgb(135, 206, 235))
  const skyPixels = new Uint8Array(4);
  gl.readPixels(0, 799, 1, 1, gl.RGBA, gl.UNSIGNED_BYTE, skyPixels);

  // Read center where anchor should be (y=3 in world maps to ~center of screen)
  const centerPixels = new Uint8Array(4);
  gl.readPixels(640, 500, 1, 1, gl.RGBA, gl.UNSIGNED_BYTE, centerPixels);

  return {
    centerPixel: [pixels[0], pixels[1], pixels[2], pixels[3]],
    topLeftPixel: [skyPixels[0], skyPixels[1], skyPixels[2], skyPixels[3]],
    anchorAreaPixel: [centerPixels[0], centerPixels[1], centerPixels[2], centerPixels[3]],
    isBlank: pixels[0] === 0 && pixels[1] === 0 && pixels[2] === 0,
    isSky: skyPixels[0] === 135 && skyPixels[1] === 206 && skyPixels[2] === 235,
  };
})()

